import{_ as i,o as a,c as e,ai as n}from"./chunks/framework.CsYGeNYI.js";const c=JSON.parse('{"title":"macOS Logging","description":"","frontmatter":{"summary":"OpenSoul logging: rolling diagnostics file log + unified log privacy flags","read_when":["Capturing macOS logs or investigating private data logging","Debugging voice wake/session lifecycle issues"],"title":"macOS Logging"},"headers":[],"relativePath":"platforms/mac/logging.md","filePath":"platforms/mac/logging.md","lastUpdated":null}'),l={name:"platforms/mac/logging.md"};function t(o,s,p,r,g,h){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="logging-macos" tabindex="-1"><a class="header-anchor" href="#logging-macos">#</a> Logging (macOS)</h1><h2 id="rolling-diagnostics-file-log-debug-pane" tabindex="-1"><a class="header-anchor" href="#rolling-diagnostics-file-log-debug-pane">#</a> Rolling diagnostics file log (Debug pane)</h2><p>OpenSoul routes macOS app logs through swift-log (unified logging by default) and can write a local, rotating file log to disk when you need a durable capture.</p><ul><li>Verbosity: <strong>Debug pane → Logs → App logging → Verbosity</strong></li><li>Enable: <strong>Debug pane → Logs → App logging → “Write rolling diagnostics log (JSONL)”</strong></li><li>Location: <code>~/Library/Logs/OpenSoul/diagnostics.jsonl</code> (rotates automatically; old files are suffixed with <code>.1</code>, <code>.2</code>, …)</li><li>Clear: <strong>Debug pane → Logs → App logging → “Clear”</strong></li></ul><p>Notes:</p><ul><li>This is <strong>off by default</strong>. Enable only while actively debugging.</li><li>Treat the file as sensitive; don’t share it without review.</li></ul><h2 id="unified-logging-private-data-on-macos" tabindex="-1"><a class="header-anchor" href="#unified-logging-private-data-on-macos">#</a> Unified logging private data on macOS</h2><p>Unified logging redacts most payloads unless a subsystem opts into <code>privacy -off</code>. Per Peter&#39;s write-up on macOS <a href="https://steipete.me/posts/2025/logging-privacy-shenanigans" target="_blank" rel="noreferrer">logging privacy shenanigans</a> (2025) this is controlled by a plist in <code>/Library/Preferences/Logging/Subsystems/</code> keyed by the subsystem name. Only new log entries pick up the flag, so enable it before reproducing an issue.</p><h2 id="enable-for-opensoul-ai-opensoul" tabindex="-1"><a class="header-anchor" href="#enable-for-opensoul-ai-opensoul">#</a> Enable for OpenSoul (<code>ai.opensoul</code>)</h2><ul><li>Write the plist to a temp file first, then install it atomically as root:</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/ai.opensoul.plist</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;!DOCTYPE plist PUBLIC &quot;-//Apple//DTD PLIST 1.0//EN&quot; &quot;http://www.apple.com/DTDs/PropertyList-1.0.dtd&quot;&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;plist version=&quot;1.0&quot;&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;key&gt;DEFAULT-OPTIONS&lt;/key&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &lt;key&gt;Enable-Private-Data&lt;/key&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &lt;true/&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;/dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/plist&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 644</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/ai.opensoul.plist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Library/Preferences/Logging/Subsystems/ai.opensoul.plist</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><ul><li>No reboot is required; logd notices the file quickly, but only new log lines will include private payloads.</li><li>View the richer output with the existing helper, e.g. <code>./scripts/opensoul-log.sh --category WebChat --last 5m</code>.</li></ul><h2 id="disable-after-debugging" tabindex="-1"><a class="header-anchor" href="#disable-after-debugging">#</a> Disable after debugging</h2><ul><li>Remove the override: <code>sudo rm /Library/Preferences/Logging/Subsystems/ai.opensoul.plist</code>.</li><li>Optionally run <code>sudo log config --reload</code> to force logd to drop the override immediately.</li><li>Remember this surface can include phone numbers and message bodies; keep the plist in place only while you actively need the extra detail.</li></ul>`,14)])])}const u=i(l,[["render",t]]);export{c as __pageData,u as default};
